solution_code:
#include <iostream>

double weightedAverage(double v1, int w1, double v2, int w2)
{
    return (v1 * w1 + v2 * w2) / (w1 + w2);
}

int main()
{
    double v1 {};
    int    w1 {};
    double v2 {};
    int    w2 {};

    std::cin >> v1 >> w1 >> v2 >> w2;

    std::cout << weightedAverage(v1, w1, v2, w2) << "\n";
    return 0;
}
